sql:
SELECT AVG(top_case_zscore) AS average_top_case_zscore
FROM genomic_datasets
WHERE gene = 'HTR5A';

external_knowledge:
Unusually low z-scores refer to values below a threshold of -1, indicating datasets with significantly lower scores than expected.;
Genetic data records are counted when the z-score threshold is met, representing outliers in the dataset.;
Z-scores below -1 are often considered significant in statistical analyses, suggesting unusually low occurrences.

sql:
SELECT COUNT(*)
FROM genomic_datasets
WHERE top_case_zscore < -1;

SELECT source, COUNT(dataset_id) AS num_datasets
FROM genomic_datasets
GROUP BY source;

SELECT dataset_id, contig, start, end, unit, gene, region, top_case_zscore, high_case_counts, data_format, source, version, created_at, updated_at, description, category, is_public, access_count
FROM genomic_datasets
WHERE is_public = 1 AND top_case_zscore > 5.0;

SELECT case_count_value
FROM case_counts
WHERE dataset_id = 1;

SELECT DISTINCT region, access_count
FROM genomic_datasets
WHERE access_count > 5 AND access_count < 10;

SELECT contig_number, description
FROM contigs
WHERE contig_number > 5;

SELECT genomic_datasets.*, units.*
FROM genomic_datasets
INNER JOIN units ON genomic_datasets.unit = units.unit_sequence;

SELECT gd.dataset_id, f.file_id, f.file_path
FROM genomic_datasets gd
INNER JOIN files f ON gd.dataset_id = f.dataset_id;

SELECT unit, gene, region
FROM genomic_datasets
WHERE unit <> '0' AND dataset_id = '0';

SELECT region 
FROM genomic_datasets 
WHERE top_case_zscore != (
  SELECT AVG(top_case_zscore) 
  FROM genomic_datasets
);
